import Redis from 'ioredis';
import { createLogger } from './logger.js';

const logger = createLogger('Config');

export const config = {
  env: process.env.NODE_ENV || 'development',

  redis: {
    host: process.env.REDIS_HOST || 'localhost',
    port: process.env.REDIS_PORT || 6379,
    password: process.env.REDIS_PASSWORD || undefined,
    db: parseInt(process.env.REDIS_DB || '0'),
    retryStrategy: (times) => Math.min(times * 50, 2000),
  },

  base44: {
    apiKey: process.env.BASE44_API_KEY,
    workspaceId: process.env.BASE44_WORKSPACE_ID,
    baseUrl: process.env.BASE44_BASE_URL || 'https://api.base44.app',
  },

  agents: {
    paymentTimeout: parseInt(process.env.PAYMENT_TIMEOUT || '30000'),
    fraudScoreThreshold: parseFloat(process.env.FRAUD_THRESHOLD || '0.7'),
    retryAttempts: parseInt(process.env.RETRY_ATTEMPTS || '3'),
    retryDelay: parseInt(process.env.RETRY_DELAY || '1000'),
  },

  logging: {
    level: process.env.LOG_LEVEL || 'info',
    format: process.env.LOG_FORMAT || 'json',
  },
};

export const redis = new Redis(config.redis);

redis.on('connect', () => logger.info('Redis connected'));
redis.on('error', (err) => logger.error('Redis error', err));

export default config;

