import winston from 'winston';
import { config } from './config.js';

const { combine, timestamp, printf, colorize, json } = winston.format;

const customFormat = printf(({ level, message, timestamp, ...meta }) => {
  return `${timestamp} [${level}] ${message} ${Object.keys(meta).length ? JSON.stringify(meta, null, 2) : ''}`;
});

export const createLogger = (label) => {
  return winston.createLogger({
    level: config.logging.level,
    format: combine(
      timestamp({ format: 'YYYY-MM-DD HH:mm:ss' }),
      config.logging.format === 'json' ? json() : customFormat,
      colorize()
    ),
    defaultMeta: { service: label },
    transports: [
      new winston.transports.Console(),
      new winston.transports.File({ filename: `logs/${label}-error.log`, level: 'error' }),
      new winston.transports.File({ filename: `logs/${label}.log` }),
    ],
  });
};

export default createLogger;

