import Redis from 'ioredis';
import { v4 as uuid } from 'uuid';
import { createLogger } from './logger.js';

const logger = createLogger('EventBroker');

export class EventBroker {
  constructor(redis) {
    this.redis = redis;
    this.pubClient = new Redis(redis.options);
    this.subClient = new Redis(redis.options);
    this.subscribers = new Map();
    this.eventHistory = [];
    this.maxHistorySize = 1000;
  }

  /**
   * Subscribe to event type
   */
  subscribe(eventType, handler, agentName) {
    const subscription = {
      id: uuid(),
      eventType,
      handler,
      agentName,
      createdAt: new Date(),
    };

    if (!this.subscribers.has(eventType)) {
      this.subscribers.set(eventType, []);
      this.subClient.subscribe(eventType, (err) => {
        if (err) logger.error(`Subscribe error for ${eventType}`, err);
      });
    }

    this.subscribers.get(eventType).push(subscription);
    logger.info(`Agent ${agentName} subscribed to ${eventType}`, { subscriptionId: subscription.id });

    return subscription.id;
  }

  /**
   * Publish event
   */
  async publish(eventType, data, source = 'system') {
    const event = {
      id: uuid(),
      type: eventType,
      data,
      source,
      timestamp: new Date().toISOString(),
    };

    this.eventHistory.push(event);
    if (this.eventHistory.length > this.maxHistorySize) {
      this.eventHistory.shift();
    }

    try {
      await this.pubClient.publish(eventType, JSON.stringify(event));
      logger.info(`Event published: ${eventType}`, { eventId: event.id, source });
      return event.id;
    } catch (err) {
      logger.error(`Failed to publish event: ${eventType}`, err);
      throw err;
    }
  }

  /**
   * Start listening to subscriptions
   */
  startListening() {
    this.subClient.on('message', (channel, message) => {
      try {
        const event = JSON.parse(message);
        const handlers = this.subscribers.get(channel) || [];

        handlers.forEach((sub) => {
          try {
            sub.handler(event).catch((err) => {
              logger.error(`Handler error for ${channel}`, { agentName: sub.agentName, error: err.message });
            });
          } catch (err) {
            logger.error(`Sync handler error for ${channel}`, { agentName: sub.agentName, error: err.message });
          }
        });
      } catch (err) {
        logger.error(`Failed to process message on ${channel}`, err);
      }
    });
  }

  /**
   * Get event history
   */
  getHistory(eventType = null, limit = 50) {
    if (eventType) {
      return this.eventHistory.filter((e) => e.type === eventType).slice(-limit);
    }
    return this.eventHistory.slice(-limit);
  }

  /**
   * Cleanup
   */
  async cleanup() {
    await this.pubClient.quit();
    await this.subClient.quit();
    logger.info('EventBroker cleaned up');
  }
}

export default EventBroker;

