import axios from 'axios';
import { createLogger } from './logger.js';
import { config } from './config.js';

const logger = createLogger('ApiClient');

export class Base44ApiClient {
  constructor(apiKey, workspaceId, baseUrl) {
    this.apiKey = apiKey;
    this.workspaceId = workspaceId;
    this.baseUrl = baseUrl;

    this.client = axios.create({
      baseURL: baseUrl,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
        'X-Workspace-ID': workspaceId,
      },
      timeout: 30000,
    });

    // Retry logic
    this.client.interceptors.response.use(
      (response) => response,
      async (error) => {
        const config = error.config;
        if (!config || !config.retry) config.retry = 0;

        config.retry += 1;

        if (config.retry <= 3 && (error.response?.status === 429 || error.response?.status >= 500)) {
          await new Promise((resolve) => setTimeout(resolve, config.retry * 1000));
          return this.client(config);
        }

        return Promise.reject(error);
      }
    );
  }

  /**
   * GET request - List records
   */
  async list(entity, query = {}) {
    try {
      const response = await this.client.get(`/entities/${entity}`, { params: query });
      logger.info(`Listed ${entity} records`, { count: response.data.length });
      return response.data;
    } catch (err) {
      logger.error(`Failed to list ${entity}`, { error: err.message });
      throw err;
    }
  }

  /**
   * GET request - Get single record by ID
   */
  async get(entity, id) {
    try {
      const response = await this.client.get(`/entities/${entity}/${id}`);
      logger.info(`Retrieved ${entity} record`, { id });
      return response.data;
    } catch (err) {
      logger.error(`Failed to get ${entity} ${id}`, { error: err.message });
      throw err;
    }
  }

  /**
   * POST request - Create record
   */
  async create(entity, data) {
    try {
      const response = await this.client.post(`/entities/${entity}`, data);
      logger.info(`Created ${entity} record`, { id: response.data.id });
      return response.data;
    } catch (err) {
      logger.error(`Failed to create ${entity}`, { error: err.message, data });
      throw err;
    }
  }

  /**
   * PUT request - Update record by ID
   */
  async update(entity, id, data) {
    try {
      const response = await this.client.put(`/entities/${entity}/${id}`, data);
      logger.info(`Updated ${entity} record`, { id });
      return response.data;
    } catch (err) {
      logger.error(`Failed to update ${entity} ${id}`, { error: err.message });
      throw err;
    }
  }

  /**
   * PATCH request - Update many records
   */
  async updateMany(entity, query, data) {
    try {
      const response = await this.client.patch(`/entities/${entity}/update-many`, {
        query,
        update: data,
      });
      logger.info(`Updated multiple ${entity} records`, { count: response.data });
      return response.data;
    } catch (err) {
      logger.error(`Failed to update many ${entity}`, { error: err.message });
      throw err;
    }
  }

  /**
   * DELETE request - Delete record by ID
   */
  async delete(entity, id) {
    try {
      await this.client.delete(`/entities/${entity}/${id}`);
      logger.info(`Deleted ${entity} record`, { id });
      return true;
    } catch (err) {
      logger.error(`Failed to delete ${entity} ${id}`, { error: err.message });
      throw err;
    }
  }

  /**
   * POST request - Bulk create
   */
  async bulkCreate(entity, records) {
    try {
      const response = await this.client.post(`/entities/${entity}/bulk`, records);
      logger.info(`Bulk created ${entity} records`, { count: records.length });
      return response.data;
    } catch (err) {
      logger.error(`Failed to bulk create ${entity}`, { error: err.message });
      throw err;
    }
  }
}

export const createApiClient = () => {
  const { apiKey, workspaceId, baseUrl } = config.base44;

  if (!apiKey || !workspaceId) {
    throw new Error('BASE44_API_KEY and BASE44_WORKSPACE_ID environment variables required');
  }

  return new Base44ApiClient(apiKey, workspaceId, baseUrl);
};

export default Base44ApiClient;

