import { createLogger } from './logger.js';

const logger = createLogger('PaymentAgent');

/**
 * PaymentAgent - Verifies payments, manages escrow, settles to sellers
 * Listens to: order.created, payment.received
 * Emits: payment.verified, payment.failed, escrow.released
 */
export class PaymentAgent {
  constructor(broker, apiClient) {
    this.broker = broker;
    this.api = apiClient;
    this.name = 'PaymentAgent';
  }

  async start() {
    logger.info('PaymentAgent started');

    // Listen for orders that need payment verification
    this.broker.subscribe('order.created', this.handleOrderCreated.bind(this), this.name);
    this.broker.subscribe('order.confirmed', this.handleOrderConfirmed.bind(this), this.name);
    this.broker.subscribe('payment.received', this.handlePaymentReceived.bind(this), this.name);
  }

  /**
   * When order created, check payment status
   */
  async handleOrderCreated(event) {
    const { data } = event;
    const { id: orderId, buyer_email, total_amount, currency } = data;

    try {
      logger.info(`Checking payment for order ${orderId}`, { buyer_email, total_amount });

      // Fetch full order details
      const order = await this.api.get('Order', orderId);

      // Check wallet balance
      const wallet = await this.api.list('Wallet', { q: JSON.stringify({ user_email: buyer_email }) });

      if (wallet.length === 0) {
        logger.warn(`No wallet found for ${buyer_email}. Order ${orderId} pending payment.`);
        await this.broker.publish('payment.pending', { orderId, buyer_email, reason: 'no_wallet' }, this.name);
        return;
      }

      const userWallet = wallet[0];
      const balanceField = currency === 'USD' ? 'balance_usd' : 'balance_ksh';

      if (userWallet[balanceField] >= total_amount) {
        // Sufficient funds - hold in escrow
        logger.info(`Escrow hold for order ${orderId}`, { amount: total_amount });

        const escrowField = currency === 'USD' ? 'escrow_usd' : 'escrow_ksh';
        const updatedWallet = {
          [balanceField]: userWallet[balanceField] - total_amount,
          [escrowField]: userWallet[escrowField] + total_amount,
        };

        await this.api.update('Wallet', userWallet.id, updatedWallet);

        // Record transaction
        await this.api.create('WalletTransaction', {
          user_email: buyer_email,
          type: 'escrow_hold',
          amount: total_amount,
          currency,
          reference_id: orderId,
          description: `Escrow hold for order ${orderId}`,
          status: 'completed',
        });

        await this.broker.publish('payment.verified', { orderId, buyer_email, amount: total_amount, currency }, this.name);
      } else {
        logger.warn(`Insufficient funds for order ${orderId}`, { balance: userWallet[balanceField], required: total_amount });
        await this.broker.publish('payment.failed', { orderId, buyer_email, reason: 'insufficient_funds' }, this.name);
      }
    } catch (err) {
      logger.error(`Payment verification failed for order ${orderId}`, err);
      await this.broker.publish('payment.failed', { orderId, error: err.message }, this.name);
    }
  }

  /**
   * When order confirmed, release escrow to seller
   */
  async handleOrderConfirmed(event) {
    const { data } = event;
    const { id: orderId, seller_email, buyer_email, total_amount, currency, payment_status } = data;

    if (payment_status !== 'escrow') {
      logger.debug(`Order ${orderId} payment not in escrow, skipping release`);
      return;
    }

    try {
      logger.info(`Releasing escrow for order ${orderId} to seller ${seller_email}`, { amount: total_amount });

