      const buyerWallet = await this.api.list('Wallet', { q: JSON.stringify({ user_email: buyer_email }) });
      if (buyerWallet.length === 0) throw new Error('Buyer wallet not found');

      const sellerWallets = await this.api.list('Wallet', { q: JSON.stringify({ user_email: seller_email }) });
      if (sellerWallets.length === 0) {
        // Create seller wallet if doesn't exist
        await this.api.create('Wallet', { user_email: seller_email, balance_ksh: 0, balance_usd: 0 });
      }

      const sellerWallet = sellerWallets[0] || (await this.api.list('Wallet', { q: JSON.stringify({ user_email: seller_email }) }))[0];
      const escrowField = currency === 'USD' ? 'escrow_usd' : 'escrow_ksh';
      const balanceField = currency === 'USD' ? 'balance_usd' : 'balance_ksh';

      // Deduct from buyer escrow
      const updatedBuyerWallet = {
        [escrowField]: Math.max(0, buyerWallet[0][escrowField] - total_amount),
      };

      // Add to seller balance
      const updatedSellerWallet = {
        [balanceField]: (sellerWallet[balanceField] || 0) + total_amount,
      };

      await this.api.update('Wallet', buyerWallet[0].id, updatedBuyerWallet);
      await this.api.update('Wallet', sellerWallet.id, updatedSellerWallet);

      // Record transactions
      await this.api.create('WalletTransaction', {
        user_email: buyer_email,
        type: 'escrow_release',
        amount: total_amount,
        currency,
        reference_id: orderId,
        status: 'completed',
      });

      await this.api.create('WalletTransaction', {
        user_email: seller_email,
        type: 'sale_credit',
        amount: total_amount,
        currency,
        reference_id: orderId,
        status: 'completed',
      });

      // Update order payment status
      await this.api.update('Order', orderId, { payment_status: 'released' });

      await this.broker.publish('payment.settled', { orderId, seller_email, amount: total_amount }, this.name);
    } catch (err) {
