import { createLogger } from '../logger.js';

const logger = createLogger('OrderAgent');

/**
 * OrderAgent - Manages order lifecycle
 * Listens to: order.created, payment.verified
 * Emits: order.confirmed, order.assigned_delivery
 */
export class OrderAgent {
  constructor(broker, apiClient) {
    this.broker = broker;
    this.api = apiClient;
    this.name = 'OrderAgent';
  }

  async start() {
    logger.info('OrderAgent started');

    this.broker.subscribe('payment.verified', this.handlePaymentVerified.bind(this), this.name);
    this.broker.subscribe('order.created', this.handleOrderCreated.bind(this), this.name);
  }

  /**
   * Auto-confirm order after payment verified
   */
  async handlePaymentVerified(event) {
    const { data } = event;
    const { orderId, buyer_email, amount } = data;

    try {
      logger.info(`Auto-confirming order ${orderId} after payment verified`);

      // Update order status
      const order = await this.api.get('Order', orderId);

      const updatedOrder = {
        status: 'confirmed',
        payment_status: 'escrow',
      };

      await this.api.update('Order', orderId, updatedOrder);

      logger.info(`Order ${orderId} confirmed`, { status: 'confirmed', payment_status: 'escrow' });

      await this.broker.publish('order.confirmed', { orderId, buyer_email, seller_email: order.seller_email }, this.name);

      // Auto-assign to delivery agent (round-robin)
      await this.assignDeliveryAgent(order);
    } catch (err) {
      logger.error(`Failed to confirm order ${orderId}`, err);
    }
  }

  /**
   * Assign order to available delivery agent
   */
  async assignDeliveryAgent(order) {
    const { id: orderId, seller_email } = order;

    try {
      logger.info(`Assigning order ${orderId} to delivery agent`);

      // Get all active delivery agents
      const deliveryAgents = await this.api.list('User', { q: JSON.stringify({ role: 'seller', account_status: 'active' }) });

      if (deliveryAgents.length === 0) {
        logger.warn(`No active delivery agents available for order ${orderId}`);
        return;
      }

      // Simple round-robin: pick random active agent
      const agent = deliveryAgents[Math.floor(Math.random() * deliveryAgents.length)];

      logger.info(`Order ${orderId} assigned to agent ${agent.email}`);

      await this.broker.publish('order.assigned_delivery', {
        orderId,
        assignedAgent: agent.email,
        agentName: agent.full_name,
      }, this.name);
    } catch (err) {
      logger.error(`Failed to assign delivery for order ${orderId}`, err);
    }
  }

  /**
   * Handle newly created orders
   */
  async handleOrderCreated(event) {
    const { data } = event;
    logger.info(`New order created: ${data.id}`, { buyer: data.buyer_email, total: data.total_amount });
  }
}

export default OrderAgent;

