import { createLogger } from '../logger.js';

const logger = createLogger('FraudAgent');

/**
 * FraudAgent - Detects suspicious activity
 * Listens to: order.created, user.signup, payment.made
 * Emits: fraud.flag, account.review_required
 */
export class FraudAgent {
  constructor(broker, apiClient) {
    this.broker = broker;
    this.api = apiClient;
    this.name = 'FraudAgent';
    this.thresholds = {
      velocity: 5, // orders per 5 min
      amount: 100000, // KSH
      newAccountOrders: 3,
    };
  }

  async start() {
    logger.info('FraudAgent started');

    this.broker.subscribe('order.created', this.handleOrderCreated.bind(this), this.name);
    this.broker.subscribe('user.signup', this.handleUserSignup.bind(this), this.name);
  }

  /**
   * Score transaction for fraud risk
   */
  async handleOrderCreated(event) {
    const { data } = event;
    const { id: orderId, buyer_email, total_amount, currency } = data;

    try {
      const score = await this.scoreTransaction(buyer_email, total_amount, currency);

      logger.info(`Fraud score for order ${orderId}`, { buyer: buyer_email, score });

      if (score > 0.7) {
        logger.warn(`HIGH FRAUD RISK for order ${orderId}`, { buyer_email, score });
        await this.broker.publish('fraud.flag', {
          orderId,
          buyer_email,
          score,
          reason: 'suspicious_transaction_pattern',
        }, this.name);

        // Flag account for review
        const users = await this.api.list('User', { q: JSON.stringify({ email: buyer_email }) });
        if (users.length > 0) {
          await this.api.update('User', users[0].id, { account_status: 'under_review' });
          await this.broker.publish('account.review_required', { user_email: buyer_email, reason: 'fraud_suspicion' }, this.name);
        }
      }
    } catch (err) {
      logger.error(`Fraud check failed for order ${orderId}`, err);
    }
  }

  /**
   * Score transaction for fraud risk (0-1)
   */
  async scoreTransaction(buyerEmail, amount, currency) {
    let score = 0;

    try {
      // Check user account age
      const users = await this.api.list('User', { q: JSON.stringify({ email: buyerEmail }) });
      if (users.length > 0) {
        const user = users[0];
        const accountAge = new Date() - new Date(user.created_date);
        const dayOld = accountAge / (1000 * 60 * 60 * 24);

        if (dayOld < 1) score += 0.4; // New account
        if (dayOld < 7) score += 0.2;
      }

      // Check transaction velocity (orders in last 5 min)
      const recentOrders = await this.api.list('Order', { q: JSON.stringify({ buyer_email: buyerEmail }) });
      const last5Min = recentOrders.filter((o) => {
        const orderTime = new Date(o.created_date);
        const now = new Date();
        return now - orderTime < 5 * 60 * 1000;
      });

      if (last5Min.length > this.thresholds.velocity) {
        score += 0.3; // High velocity
      }

      // Check amount threshold
      const threshold = currency === 'USD' ? 500 : this.thresholds.amount;
      if (amount > threshold) {
        score += 0.15;
      }

      // Check if verified
      if (users.length > 0 && !users[0].is_verified) {
        score += 0.1;
      }

      return Math.min(score, 1);
    } catch (err) {
      logger.warn(`Could not fully score transaction for ${buyerEmail}`, err.message);
      return 0.3; // Default caution
    }
  }

  async handleUserSignup(event) {
    const { data } = event;
    logger.info(`New user signup: ${data.email}`);
  }
}

export default FraudAgent;

