import { createLogger } from '../logger.js';

const logger = createLogger('InventoryAgent');

/**
 * InventoryAgent - Syncs product availability
 * Listens to: order.confirmed, product.restock
 * Emits: inventory.updated, low_stock.alert
 */
export class InventoryAgent {
  constructor(broker, apiClient) {
    this.broker = broker;
    this.api = apiClient;
    this.name = 'InventoryAgent';
    this.lowStockThreshold = 5;
  }

  async start() {
    logger.info('InventoryAgent started');

    this.broker.subscribe('order.confirmed', this.handleOrderConfirmed.bind(this), this.name);
    this.broker.subscribe('product.restock', this.handleProductRestock.bind(this), this.name);
  }

  /**
   * Decrement stock when order confirmed
   */
  async handleOrderConfirmed(event) {
    const { data } = event;
    const { orderId, items } = data;

    try {
      if (!items || items.length === 0) {
        logger.warn(`Order ${orderId} has no items`);
        return;
      }

      logger.info(`Updating inventory for order ${orderId}`, { itemCount: items.length });

      for (const item of items) {
        const { product_id, quantity } = item;

        try {
          const product = await this.api.get('Product', product_id);

          const newQuantity = Math.max(0, (product.stock_quantity || 0) - quantity);

          let newStatus = 'in_stock';
          if (newQuantity === 0) newStatus = 'out_of_stock';
          else if (newQuantity <= this.lowStockThreshold) newStatus = 'low_stock';

          await this.api.update('Product', product_id, {
            stock_quantity: newQuantity,
            stock_status: newStatus,
          });

          logger.info(`Inventory updated for product ${product_id}`, { newQuantity, newStatus });

          if (newStatus === 'low_stock') {
            await this.broker.publish('low_stock.alert', {
              product_id,
              product_name: product.name,
              seller_email: product.seller_email,
              quantity: newQuantity,
            }, this.name);
          }

          await this.broker.publish('inventory.updated', {
            product_id,
            new_quantity: newQuantity,
            status: newStatus,
          }, this.name);
        } catch (err) {
          logger.error(`Failed to update inventory for product ${product_id}`, err);
        }
      }
    } catch (err) {
      logger.error(`Inventory sync failed for order ${orderId}`, err);
    }
  }

  /**
   * Handle product restock
   */
  async handleProductRestock(event) {
    const { data } = event;
    const { product_id, quantity } = data;

    try {
      logger.info(`Product restock: ${product_id}, quantity: ${quantity}`);

      const product = await this.api.get('Product', product_id);
      const newQuantity = (product.stock_quantity || 0) + quantity;

      let newStatus = 'in_stock';
      if (newQuantity === 0) newStatus = 'out_of_stock';
      else if (newQuantity > this.lowStockThreshold) newStatus = 'in_stock';

      await this.api.update('Product', product_id, {
        stock_quantity: newQuantity,
        stock_status: newStatus,
      });

      await this.broker.publish('inventory.updated', {
        product_id,
        new_quantity: newQuantity,
        status: newStatus,
        type: 'restock',
      }, this.name);

      logger.info(`Product ${product_id} restocked`, { newQuantity, newStatus });
    } catch (err) {
      logger.error(`Restock failed for product ${product_id}`, err);
    }
  }
}

export default InventoryAgent;

