import { createLogger } from '../logger.js';

const logger = createLogger('VerificationAgent');

/**
 * VerificationAgent - Handles user verification flows
 * Listens to: user.signup, account.review_required
 * Emits: user.verified, user.pending_review
 */
export class VerificationAgent {
  constructor(broker, apiClient) {
    this.broker = broker;
    this.api = apiClient;
    this.name = 'VerificationAgent';
  }

  async start() {
    logger.info('VerificationAgent started');

    this.broker.subscribe('user.signup', this.handleUserSignup.bind(this), this.name);
    this.broker.subscribe('account.review_required', this.handleReviewRequired.bind(this), this.name);
  }

  /**
   * Auto-verify low-risk users
   */
  async handleUserSignup(event) {
    const { data } = event;
    const { user_email, full_name, role } = data;

    try {
      logger.info(`Processing signup for ${user_email}`, { role });

      const users = await this.api.list('User', { q: JSON.stringify({ email: user_email }) });

      if (users.length === 0) {
        logger.warn(`User not found: ${user_email}`);
        return;
      }

      const user = users[0];
      const riskScore = this.calculateRiskScore(user);

      logger.info(`User risk score: ${user_email}`, { riskScore });

      if (riskScore < 0.3) {
        // Auto-verify low-risk users
        await this.api.update('User', user.id, {
          is_verified: true,
          account_status: 'active',
        });

        logger.info(`Auto-verified user: ${user_email}`);
        await this.broker.publish('user.verified', { user_email, auto: true }, this.name);
      } else if (riskScore < 0.7) {
        // Mark for manual review
        await this.api.update('User', user.id, { account_status: 'under_review' });

        logger.info(`User marked for review: ${user_email}`);
        await this.broker.publish('user.pending_review', { user_email, riskScore }, this.name);
      } else {
        // High risk - reject or flag
        await this.api.update('User', user.id, {
          account_status: 'suspended',
        });

        logger.warn(`User suspended - high risk: ${user_email}`);
        await this.broker.publish('user.rejected', { user_email, riskScore, reason: 'high_risk' }, this.name);
      }
    } catch (err) {
      logger.error(`User signup verification failed: ${user_email}`, err);
    }
  }

  /**
   * Handle account review requests
   */
  async handleReviewRequired(event) {
    const { data } = event;
    const { user_email, reason } = data;

    try {
      logger.info(`Review required for user: ${user_email}`, { reason });

      const users = await this.api.list('User', { q: JSON.stringify({ email: user_email }) });

      if (users.length === 0) return;

      const user = users[0];

      // Mark as under review
      await this.api.update('User', user.id, { account_status: 'under_review' });

      logger.info(`Account ${user_email} flagged for review`, { reason });
    } catch (err) {
      logger.error(`Review handling failed for ${user_email}`, err);
    }
  }

  /**
   * Calculate user risk score (0-1)
   */
  calculateRiskScore(user) {
    let score = 0;

    // Account age
    const accountAge = new Date() - new Date(user.created_date);
    const hoursOld = accountAge / (1000 * 60 * 60);

    if (hoursOld < 1) score += 0.4;
    if (hoursOld < 24) score += 0.2;

    // Verification status
    if (!user.is_verified) score += 0.3;

    // Role-based check
    if (user.role === 'seller') score += 0.1; // Sellers need more verification

    // Missing info
    if (!user.business_name && user.role === 'seller') score += 0.15;
    if (!user.phone) score += 0.05;

    return Math.min(score, 1);
  }
}

export default VerificationAgent;

