import { config, redis } from './config.js';
import { createLogger } from './logger.js';
import { createApiClient } from './ApiClient.js';
import { EventBroker } from './EventBroker.js';
import { PaymentAgent } from './agents/PaymentAgent.js';
import { OrderAgent } from './agents/OrderAgent.js';
import { FraudAgent } from './agents/FraudAgent.js';
import { InventoryAgent } from './agents/InventoryAgent.js';
import { VerificationAgent } from './agents/VerificationAgent.js';

const logger = createLogger('Main');

async function main() {
  try {
    logger.info('🚀 Traxist Agent System Starting', { env: config.env });

    // Initialize API client
    const apiClient = createApiClient();
    logger.info('✅ API Client initialized');

    // Initialize Event Broker
    const broker = new EventBroker(redis);
    broker.startListening();
    logger.info('✅ Event Broker initialized and listening');

    // Initialize and start all agents
    const agents = [
      new PaymentAgent(broker, apiClient),
      new OrderAgent(broker, apiClient),
      new FraudAgent(broker, apiClient),
      new InventoryAgent(broker, apiClient),
      new VerificationAgent(broker, apiClient),
    ];

    for (const agent of agents) {
      await agent.start();
    }

    logger.info('✅ All agents started and listening', { agentCount: agents.length });

    // Graceful shutdown
    process.on('SIGINT', async () => {
      logger.info('🛑 Shutting down gracefully...');
      await broker.cleanup();
      await redis.quit();
      process.exit(0);
    });

    logger.info('🎯 Traxist Agent System is running and ready!');
  } catch (err) {
    logger.error('❌ Fatal error starting system', err);
    process.exit(1);
  }
}

main();

