import Redis from 'ioredis';

/**
 * Test utility - publish test events to Redis
 * Usage: node tests/publishTestEvents.js
 */

const redis = new Redis({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
});

const testEvents = [
  {
    name: 'New User Signup',
    event: 'user.signup',
    data: {
      user_email: 'newuser@example.com',
      full_name: 'John Doe',
      role: 'buyer',
    },
  },
  {
    name: 'Order Created',
    event: 'order.created',
    data: {
      id: 'order-' + Date.now(),
      buyer_email: 'buyer@example.com',
      seller_email: 'seller@example.com',
      total_amount: 5000,
      currency: 'KSH',
      items: [
        { product_id: 'prod-1', name: 'Item 1', quantity: 2, price: 2500 },
      ],
    },
  },
  {
    name: 'Payment Verified',
    event: 'payment.verified',
    data: {
      orderId: 'order-123',
      buyer_email: 'buyer@example.com',
      amount: 5000,
      currency: 'KSH',
    },
  },
  {
    name: 'Product Restock',
    event: 'product.restock',
    data: {
      product_id: 'prod-1',
      quantity: 50,
    },
  },
];

async function publishEvent(event, data) {
  try {
    const message = JSON.stringify({
      id: require('uuid').v4(),
      type: event,
      data,
      source: 'test',
      timestamp: new Date().toISOString(),
    });

    await redis.publish(event, message);
    console.log(`✅ Published: ${event}`);
    console.log(`   Data: ${JSON.stringify(data, null, 2)}\n`);
  } catch (err) {
    console.error(`❌ Failed to publish ${event}:`, err.message);
  }
}

async function runTests() {
  console.log('🧪 Publishing Test Events to Traxist Agents\n');
  console.log('Make sure agents are running in another terminal!\n');

  for (const test of testEvents) {
    console.log(`→ ${test.name}`);
    await publishEvent(test.event, test.data);
    await new Promise((resolve) => setTimeout(resolve, 1000));
  }

  console.log('\n✅ All test events published!');
  console.log('Check agent logs for processing...\n');

  redis.disconnect();
}

runTests().catch(console.error);

